const express = require('express');
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const MongoStore = require('rate-limit-mongo');

const app = express();
app.use(express.json());

// MongoDB User Schema
const userSchema = new mongoose.Schema({
  username: { type: String, required: true, unique: true, index: true },
  password: { type: String, required: true },
  loginAttempts: { type: Number, default: 0 },
  lockUntil: { type: Date }
});

userSchema.virtual('isLocked').get(function() {
  return !!(this.lockUntil && this.lockUntil > Date.now());
});

userSchema.methods.incLoginAttempts = function() {
  const MAX_LOGIN_ATTEMPTS = 5;
  const LOCK_TIME = 15 * 60 * 1000; // 15 minutes

  if (this.lockUntil && this.lockUntil < Date.now()) {
    return this.updateOne({
      $set: { loginAttempts: 1 },
      $unset: { lockUntil: 1 }
    });
  }

  const updates = { $inc: { loginAttempts: 1 } };
  const isMaxAttempts = this.loginAttempts + 1 >= MAX_LOGIN_ATTEMPTS;

  if (isMaxAttempts && !this.isLocked) {
    updates.$set = { lockUntil: Date.now() + LOCK_TIME };
  }

  return this.updateOne(updates);
};

userSchema.methods.resetLoginAttempts = function() {
  return this.updateOne({
    $set: { loginAttempts: 0 },
    $unset: { lockUntil: 1 }
  });
};

const User = mongoose.model('User', userSchema);

// Rate limiting with MongoDB store for distributed systems
const loginLimiter = rateLimit({
  store: new MongoStore({
    uri: process.env.MONGODB_URI || 'mongodb://localhost:27017/auth',
    collectionName: 'rateLimits',
    expireTimeMs: 15 * 60 * 1000
  }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 requests per window per IP
  skipSuccessfulRequests: false,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    res.status(429).json({
      success: false,
      message: 'Authentication service temporarily unavailable. Please try again later.'
    });
  }
});

// Additional global rate limiter for the entire API
const globalLimiter = rateLimit({
  windowMs: 1 * 60 * 1000, // 1 minute
  max: 30, // 30 requests per minute per IP
  standardHeaders: true,
  legacyHeaders: false
});

app.use(globalLimiter);

// Login endpoint with comprehensive security controls
app.post('/api/login', loginLimiter, async (req, res) => {
  const GENERIC_ERROR = 'Invalid credentials. Please try again.';
  const ACCOUNT_LOCKED_ERROR = 'Authentication service temporarily unavailable. Please try again later.';
  const RESPONSE_DELAY = 1000; // 1 second delay to prevent timing attacks
  
  const startTime = Date.now();

  try {
    const { username, password } = req.body;

    // Input validation
    if (!username || !password || 
        typeof username !== 'string' || typeof password !== 'string' ||
        username.length > 100 || password.length > 100) {
      await delayResponse(startTime, RESPONSE_DELAY);
      return res.status(401).json({
        success: false,
        message: GENERIC_ERROR
      });
    }

    // Find user with constant-time lookup consideration
    const user = await User.findOne({ username: username.toLowerCase().trim() });

    // Check if account is locked (anti-enumeration: don't reveal if user exists)
    if (user && user.isLocked) {
      await delayResponse(startTime, RESPONSE_DELAY);
      return res.status(401).json({
        success: false,
        message: ACCOUNT_LOCKED_ERROR
      });
    }

    // Verify password (always run bcrypt even if user doesn't exist to prevent timing attacks)
    const dummyHash = '$2a$10$N9qo8uLOickgx2ZMRZoMyeIjZAgcfl7p92ldGxad68LJZdL17lhWy';
    const passwordHash = user ? user.password : dummyHash;
    const isValidPassword = await bcrypt.compare(password, passwordHash);

    // Handle invalid credentials
    if (!user || !isValidPassword) {
      if (user) {
        await user.incLoginAttempts();
      }
      await delayResponse(startTime, RESPONSE_DELAY);
      return res.status(401).json({
        success: false,
        message: GENERIC_ERROR
      });
    }

    // Reset login attempts on successful login
    await user.resetLoginAttempts();

    // Generate JWT token
    const token = jwt.sign(
      { 
        userId: user._id,
        username: user.username
      },
      process.env.JWT_SECRET || 'your-secret-key-change-in-production',
      { 
        expiresIn: '24h',
        issuer: 'auth-service',
        audience: 'mobile-app'
      }
    );

    await delayResponse(startTime, RESPONSE_DELAY);

    res.json({
      success: true,
      token,
      expiresIn: 86400
    });

  } catch (error) {
    console.error('Login error:', error);
    await delayResponse(startTime, RESPONSE_DELAY);
    res.status(500).json({
      success: false,
      message: 'An error occurred. Please try again later.'
    });
  }
});

// Helper function to ensure consistent response timing
async function delayResponse(startTime, targetDelay) {
  const elapsed = Date.now() - startTime;
  const remaining = targetDelay - elapsed;
  if (remaining > 0) {
    await new Promise(resolve => setTimeout(resolve, remaining));
  }
}

// MongoDB connection
mongoose.connect(process.env.MONGODB_URI || 'mongodb://localhost:27017/auth', {
  useNewUrlParser: true,
  useUnifiedTopology: true
}).then(() => {
  console.log('Connected to MongoDB');
}).catch(err => {
  console.error('MongoDB connection error:', err);
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Auth service running on port ${PORT}`);
});

module.exports = app;